using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using ValoraPesquisa.Application.Contracts; using ValoraPesquisa.Domain.Entities; using ValoraPesquisa.Domain.Enums;
namespace ValoraPesquisa.Api.Controllers;
[ApiController,Authorize,Route("plans")] public sealed class PlansController(IPlanService svc,IAuditService audit):ApiBase{[HttpGet]public Task<IReadOnlyList<ValoraPesquisa.Application.DTOs.PlanDto>> Get()=>svc.ListAsync();[HttpGet("{code}")]public async Task<IActionResult> Get(string code)=>await svc.GetAsync(code) is{} p?Ok(p):NotFound();[HttpPost]public async Task<IActionResult> Post(PlanInput i){var p=await svc.CreateAsync(new Plan(Guid.NewGuid(),i.Code,i.Name,i.Description,i.MonthlyPrice,i.AnnualPrice,i.Status??"active",i.DisplayOrder,DateTimeOffset.UtcNow,null,false),Current());await audit.RecordAsync(null,Current().Id,"plan_created","plan",p.Id,Cid,new{p.Code});return Ok(p);}[HttpPut("{id:guid}")]public async Task<IActionResult> Put(Guid id,PlanInput i){var p=await svc.UpdateAsync(new Plan(id,i.Code,i.Name,i.Description,i.MonthlyPrice,i.AnnualPrice,i.Status??"active",i.DisplayOrder,DateTimeOffset.UtcNow,DateTimeOffset.UtcNow,false),Current());await audit.RecordAsync(null,Current().Id,"plan_edited","plan",p.Id,Cid,new{p.Code});return Ok(p);}[HttpGet("{code}/limits")]public Task<ValoraPesquisa.Application.DTOs.PlanLimitDto?> Limits(string code)=>svc.LimitsAsync(code);[HttpGet("{code}/capabilities")]public Task<IReadOnlyList<ValoraPesquisa.Application.DTOs.PlanCapabilityDto>> Caps(string code)=>svc.CapabilitiesAsync(code);} public record PlanInput(string Code,string Name,string? Description,decimal MonthlyPrice,decimal AnnualPrice,string? Status,int DisplayOrder);
[ApiController,Authorize,Route("modules")] public sealed class ModulesController(IModuleService svc,IAuditService audit):ApiBase{[HttpGet]public Task<IReadOnlyList<ValoraPesquisa.Application.DTOs.ModuleDto>> Get()=>svc.ListAsync();[HttpGet("/organizations/{organizationId:guid}/modules")]public Task<IReadOnlyList<ValoraPesquisa.Application.DTOs.OrganizationModuleDto>> Org(Guid organizationId)=>svc.ForOrganizationAsync(organizationId);[HttpPut("/organizations/{organizationId:guid}/modules/{moduleCode}")]public async Task<IActionResult> Set(Guid organizationId,string moduleCode,ModuleToggleInput i){var m=await svc.SetForOrganizationAsync(organizationId,moduleCode,i.Enabled,i.Source??"manual",Current());await audit.RecordAsync(organizationId,Current().Id,i.Enabled?"module_enabled":"module_disabled","module",m.ModuleId,Cid,new{moduleCode,i.Enabled});return Ok(m);}} public record ModuleToggleInput(bool Enabled,string? Source);
[ApiController,Authorize,Route("organizations/{organizationId:guid}/subscription")] public sealed class SubscriptionsController(ISubscriptionService svc,IAuditService audit):ApiBase{[HttpGet]public Task<ValoraPesquisa.Application.DTOs.SubscriptionDto?> Get(Guid organizationId)=>svc.CurrentAsync(organizationId);[HttpPut]public async Task<IActionResult> Put(Guid organizationId,SubscriptionPlanInput i){var s=await svc.ChangePlanAsync(organizationId,i.PlanCode,Current());await audit.RecordAsync(organizationId,Current().Id,"subscription_plan_changed","subscription",s.Id,Cid,new{i.PlanCode});return Ok(s);}[HttpPatch("status")]public async Task<IActionResult> Status(Guid organizationId,SubscriptionStatusInput i){var s=await svc.ChangeStatusAsync(organizationId,i.Status,i.BillingStatus,Current());await audit.RecordAsync(organizationId,Current().Id,i.Status=="suspended"?"subscription_suspended":"subscription_status_changed","subscription",s.Id,Cid,new{i.Status,i.BillingStatus});return Ok(s);}} public record SubscriptionPlanInput(string PlanCode); public record SubscriptionStatusInput(string Status,string BillingStatus);
[ApiController,Authorize,Route("organizations/{organizationId:guid}/usage")] public sealed class UsageController(IUsageService svc,IPermissionService permissions):ApiBase{[HttpGet]public async Task<IActionResult> Get(Guid organizationId){var p=permissions.Can(Current(),SaasActions.ViewUsage,organizationId); if(!p.Allowed)return Forbid(); return Ok(await svc.CurrentAsync(organizationId));}[HttpPost("recalculate")]public async Task<IActionResult> Recalc(Guid organizationId){var p=permissions.Can(Current(),SaasActions.ViewUsage,organizationId); if(!p.Allowed)return Forbid(); return Ok(await svc.RecalculateAsync(organizationId));}}
[ApiController,Authorize,Route("organizations/{organizationId:guid}")] public sealed class EntitlementsController(IEntitlementService svc):ApiBase{[HttpGet("entitlements")]public async Task<IActionResult> All(Guid organizationId)=>Ok(new{subscription=await svc.HasActiveSubscriptionAsync(organizationId),formularios=await svc.CanCreateFormAsync(organizationId),pesquisas=await svc.CanCreateSurveyAsync(organizationId),usuarios=await svc.CanCreateUserAsync(organizationId),links=await svc.CanCreateLinkAsync(organizationId),respostas=await svc.CanRegisterResponseAsync(organizationId)});[HttpGet("can-use/{moduleCode}")]public Task<ValoraPesquisa.Application.DTOs.EntitlementResultDto> CanUse(Guid organizationId,string moduleCode)=>svc.CanUseModuleAsync(organizationId,moduleCode);[HttpGet("can-create-survey")]public Task<ValoraPesquisa.Application.DTOs.EntitlementResultDto> Survey(Guid organizationId)=>svc.CanCreateSurveyAsync(organizationId);[HttpGet("can-create-form")]public Task<ValoraPesquisa.Application.DTOs.EntitlementResultDto> Form(Guid organizationId)=>svc.CanCreateFormAsync(organizationId);[HttpGet("can-create-user")]public Task<ValoraPesquisa.Application.DTOs.EntitlementResultDto> User(Guid organizationId)=>svc.CanCreateUserAsync(organizationId);[HttpGet("can-create-link")]public Task<ValoraPesquisa.Application.DTOs.EntitlementResultDto> Link(Guid organizationId)=>svc.CanCreateLinkAsync(organizationId);}
[ApiController,Authorize,Route("dashboard")] public sealed class DashboardController(IDashboardMetricsService svc):ApiBase{[HttpGet("global")]public Task<ValoraPesquisa.Application.DTOs.DashboardGlobalDto> Global()=>svc.GlobalAsync(Current());[HttpGet("organization")]public Task<ValoraPesquisa.Application.DTOs.DashboardOrganizationDto> Org(Guid? organizationId)=>svc.OrganizationAsync(Current(),organizationId);}
[ApiController,Authorize,Route("me/menu")] public sealed class MenuController(IMenuService svc):ApiBase{[HttpGet]public Task<IReadOnlyList<ValoraPesquisa.Application.DTOs.MenuItemDto>> Get()=>svc.GetMenuAsync(Current());}
